// src/components/TelaAlunos.js
import React, { useState, useEffect } from "react";
import axios from "axios";
import Modal from './Modal';
import FormAluno from "./FormAluno";

export default function TelaAlunos() {
  const [alunos, setAlunos] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [mostrarModal, setMostrarModal] = useState(false);
  const [alunoEditando, setAlunoEditando] = useState(null);

  // Carregar lista de alunos
  useEffect(() => {
    setCarregando(true);
    axios.get('/api/alunos')
      .then(res => {
        setAlunos(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }, []);

  function recarregarAlunos() {
    setCarregando(true);
    axios.get('/api/alunos')
      .then(res => {
        setAlunos(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }

  function onEditar(aluno) {
    setAlunoEditando(aluno);
    setMostrarModal(true);
  }

  function onNovo() {
    recarregarAlunos();
  }

  function onFecharModal() {
    setAlunoEditando(null);
    setMostrarModal(false);
  }

  if (carregando) return <p>Carregando alunos...</p>;
  if (alunos.length === 0) return <p>Nenhum aluno cadastrado.</p>;

  return (
    <div className="mt-4">
      <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">
        Lista de Alunos
      </h2>
      <button
        className="mb-4 bg-green-500 text-white px-4 py-2 rounded-full"
        onClick={() => setMostrarModal(true)}
      >
        Cadastrar Novo Aluno
      </button>
      {/* Cabeçalho de colunas */}
      <div className="flex px-5 pb-2 text-gray-500 font-bold text-sm">
        <div className="w-1/4">Nome</div>
        <div className="w-1/6">RA</div>
        <div className="w-1/6">Usuário</div>
        <div className="w-1/6">Perfil</div>
        <div className="w-1/6">Período</div>
        <div className="w-1/6 text-right">Ações</div>
      </div>
      <ul className="space-y-3">
        {alunos.map(a => (
          <li
            key={a.id}
            className="flex items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
          >
            <div className="w-1/4 font-medium text-gray-800 truncate">{a.nome}</div>
            <div className="w-1/6 text-gray-500">{a.ra}</div>
            <div className="w-1/6 text-gray-500">{a.usuario}</div>
            <div className="w-1/6 text-gray-500">{a.role}</div>
            <div className="w-1/6 text-gray-500">
              {a.periodo_nome} {a.turno}
            </div>
            <div className="w-1/6 flex justify-end space-x-2">
              <button
                onClick={() => onEditar(a)}
                className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
              >
                Editar
              </button>
              <button
                onClick={() => {
                  if(window.confirm('Tem certeza que deseja deletar este aluno?')) {
                    axios.delete(`/api/alunos/${a.id}`).then(() => recarregarAlunos());
                  }
                }}
                className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
              >
                Deletar
              </button>
            </div>
          </li>
        ))}
      </ul>

      {mostrarModal && (
        <Modal isOpen={mostrarModal} onRequestClose={onFecharModal}>
          <FormAluno
            alunoEditando={alunoEditando}
            onNovoAluno={onNovo}
            onFimEdicao={onFecharModal}
          />
        </Modal>
      )}
    </div>
  );
}
